    "change_intelligence.intake.record_label": "Fremder Änderungsdatensatz (JSON)",
    "change_intelligence.intake.profile_label": "Erfassungsprofil",
    "change_intelligence.intake.reading": "Wird gelesen...",
    "change_intelligence.intake.preview": "Vorschau",
    "change_intelligence.intake.helper": "Fügen Sie eine Zeile aus einer Tracker-Tabelle oder einem E-Mail-Erfassungsformular ein. Der Datensatz wird zu einem kanonischen Änderungsentwurf normalisiert, nur zur Vorschau - es wird nichts gespeichert.",
    "change_intelligence.intake.empty_title": "Kanonischer Entwurf",
    "change_intelligence.intake.empty_desc": "Schauen Sie einen fremden Datensatz vorab an, um Titel, Kosten, Terminauswirkung und das, was nicht zugeordnet werden konnte, zu sehen.",
    "change_intelligence.intake.no_title": "(kein Titel)",
