    "change_intelligence.intake.requested_by": "Angefordert von",
    "change_intelligence.intake.reference": "Referenz",
    "change_intelligence.intake.missing_required": "Pflichtfeld fehlt",
    "change_intelligence.intake.unmapped_columns": "Nicht zugeordnete Spalten",
