    "change_intelligence.delay.tile.elevated": "Erhöht",
    "change_intelligence.delay.tile.low": "Niedrig",
    "change_intelligence.delay.empty_title": "Keine offenen Änderungen",
    "change_intelligence.delay.empty_desc": "Es gibt derzeit keine offenen Änderungen, deren Verzugsrisiko bewertet werden könnte.",
    "change_intelligence.delay.risk_pct": "{{pct}}% Risiko",
    "change_intelligence.delay.overdue": "überfällig",
