    "dashboards.snapshots_subtitle": "Frieren Sie ein Parquet-Dataset aus Ihren CAD/BIM-Dateien ein und vergleichen Sie Snapshots im Zeitverlauf.",
    "dashboards.view_list": "Schnappschüsse",
